<script setup lang="ts">
import { computed, onMounted, reactive, ref } from "vue";
import { UiTable, type UiTableColumn } from "@moecraft/ui";
import type { AdminButtonPermission, CatalogOverview, ProductDraftInput, ProductDraftListItem, ProductDraftView } from "@moecraft/shared";
import { apiRequest } from "../../../api";

const props=withDefaults(defineProps<{buttonPermissions?:AdminButtonPermission[]}>(),{buttonPermissions:()=>[]});
const products=ref<ProductDraftListItem[]>([]);const catalog=ref<CatalogOverview|null>(null);const loading=ref(true);const busy=ref(false);const error=ref("");const keyword=ref("");const status=ref("ALL");const modal=ref(false);const editingId=ref<string|null>(null);
const columns:UiTableColumn[]=[{key:"product",label:"商品",width:"34%"},{key:"status",label:"状态",width:"12%"},{key:"sku",label:"SKU / 库存",width:"18%"},{key:"price",label:"价格区间",width:"16%"},{key:"updated",label:"更新时间",width:"12%"},{key:"actions",label:"操作",width:"18%",align:"right"}];
const empty=():ProductDraftInput=>({titleZhCn:"",titleEnUs:"",descriptionZhCn:"",descriptionEnUs:"",categoryId:"",brandId:"",franchiseId:"",characterId:"",tagIds:[],material:"",scale:"",manufacturer:"",copyrightNotice:"",skus:[],media:[]});
const form=reactive<ProductDraftInput>(empty());
const canManage=computed(()=>props.buttonPermissions.includes("products.manage"));
const rows=computed(()=>products.value.filter(item=>(status.value==="ALL"||item.status===status.value)&&(`${item.titleZhCn} ${item.titleEnUs??""}`).toLowerCase().includes(keyword.value.toLowerCase())).map(item=>({...item,product:item.titleZhCn,sku:item.skuCount,price:item.priceMin,updated:item.updatedAt,actions:item.id})));
function reset(value:ProductDraftInput=empty()){for(const key of Object.keys(form))delete (form as unknown as Record<string,unknown>)[key];Object.assign(form,empty(),structuredClone({titleZhCn:value.titleZhCn,titleEnUs:value.titleEnUs,descriptionZhCn:value.descriptionZhCn,descriptionEnUs:value.descriptionEnUs,categoryId:value.categoryId,brandId:value.brandId,franchiseId:value.franchiseId,characterId:value.characterId,tagIds:value.tagIds,material:value.material,scale:value.scale,manufacturer:value.manufacturer,copyrightNotice:value.copyrightNotice,skus:value.skus,media:value.media}));}
function payload():ProductDraftInput{return{titleZhCn:form.titleZhCn,titleEnUs:form.titleEnUs,descriptionZhCn:form.descriptionZhCn,descriptionEnUs:form.descriptionEnUs,categoryId:form.categoryId,brandId:form.brandId,franchiseId:form.franchiseId,characterId:form.characterId,tagIds:[...form.tagIds],material:form.material,scale:form.scale,manufacturer:form.manufacturer,copyrightNotice:form.copyrightNotice,skus:form.skus.map(({id:_,...sku})=>({...sku,optionValues:{...sku.optionValues}})),media:form.media.map(({id:_,...media})=>({...media}))};}
async function load(){loading.value=true;error.value="";try{[products.value,catalog.value]=await Promise.all([apiRequest<ProductDraftListItem[]>("/merchant/products"),apiRequest<CatalogOverview>("/catalog/public")]);}catch(e){error.value=(e as {message?:string}).message??"商品数据加载失败";}finally{loading.value=false;}}
function create(){editingId.value=null;reset();modal.value=true;}
async function edit(id:string){busy.value=true;try{const item=await apiRequest<ProductDraftView>(`/merchant/products/${id}`);editingId.value=id;reset(item);modal.value=true;}catch(e){error.value=(e as {message?:string}).message??"商品读取失败";}finally{busy.value=false;}}
function addSku(){form.skus.push({code:`MC-${crypto.randomUUID().slice(0,8).toUpperCase()}`,nameZhCn:"",optionValues:{},priceAmount:0,currency:"CNY",initialStock:0});}
function addMedia(){form.media.push({fileId:"",kind:"IMAGE",sortOrder:form.media.length,isCover:!form.media.length});}
function setCover(index:number){form.media.forEach((item,i)=>item.isCover=i===index);}
async function save(){error.value="";if(!form.titleZhCn.trim()){error.value="请填写必填项：中文标题。";return;}const incompleteSku=form.skus.findIndex(item=>!item.nameZhCn.trim());if(incompleteSku>=0){error.value=`请填写第 ${incompleteSku+1} 个 SKU 的规格名称，商家编码留空时由系统生成。`;return;}busy.value=true;try{await apiRequest(editingId.value?`/merchant/products/${editingId.value}`:"/merchant/products",{method:editingId.value?"PUT":"POST",body:JSON.stringify(payload())});modal.value=false;await load();}catch(e){error.value=(e as {message?:string}).message??"草稿保存失败，请检查标有 * 的必填项。";}finally{busy.value=false;}}
async function archive(id:string){if(!confirm("确定归档这个商品草稿？"))return;try{await apiRequest(`/merchant/products/${id}`,{method:"DELETE"});await load();}catch(e){error.value=(e as {message?:string}).message??"归档失败";}}
function money(value?:number){return value===undefined?"—":new Intl.NumberFormat("zh-CN",{style:"currency",currency:"CNY"}).format(value/100);}
onMounted(load);
</script>

<template><section class="product-page content-scroll"><div class="shell"><header class="hero"><div><small>PRODUCT STUDIO</small><h1>商品管理</h1><p>维护多语言商品资料、SKU 规格、初始库存与展示媒体。草稿可以随时保存。</p></div><button v-if="canManage" @click="create">＋ 新建商品草稿</button></header><p v-if="error" class="error">{{error}}</p><section class="panel"><div class="filters"><input v-model="keyword" placeholder="搜索商品名称"><select v-model="status"><option value="ALL">全部状态</option><option value="DRAFT">草稿</option><option value="REJECTED">已驳回</option><option value="PENDING_REVIEW">待审核</option><option value="ACTIVE">在售</option></select></div><div v-if="loading" class="loading">正在加载商品…</div><UiTable v-else :columns="columns" :rows="rows" empty-text="暂无商品草稿"><template #cell-product="{row}"><div class="name"><b>{{row.titleZhCn}}</b><small>{{row.titleEnUs||row.categoryName||'资料待完善'}}</small></div></template><template #cell-status="{row}"><em>{{row.status}}</em></template><template #cell-sku="{row}">{{row.skuCount}} 个 / {{row.stock}} 件</template><template #cell-price="{row}">{{money(row.priceMin as number|undefined)}}<span v-if="row.priceMax!==row.priceMin"> – {{money(row.priceMax as number|undefined)}}</span></template><template #cell-updated="{row}">{{new Date(row.updatedAt as string).toLocaleDateString()}}</template><template #cell-actions="{row}"><div class="actions"><button @click="edit(row.id as string)">查看/编辑</button><button v-if="canManage&&['DRAFT','REJECTED','INACTIVE'].includes(row.status as string)" class="danger" @click="archive(row.id as string)">归档</button></div></template></UiTable></section></div>
<Teleport to="body"><div v-if="modal" class="mask" @mousedown.self="modal=false"><form class="drawer" @submit.prevent="save"><header><div><small>PRODUCT DRAFT</small><h2>{{editingId?'编辑商品草稿':'新建商品草稿'}}</h2></div><button type="button" @click="modal=false">×</button></header><div class="form-scroll"><h3>基础资料</h3><div class="grid"><label><span>中文标题 *</span><input v-model="form.titleZhCn" required></label><label><span>英文标题</span><input v-model="form.titleEnUs"></label><label><span>类目</span><select v-model="form.categoryId"><option value="">草稿暂不选择</option><option v-for="item in catalog?.categories" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label><span>品牌</span><select v-model="form.brandId"><option value="">未选择</option><option v-for="item in catalog?.brands" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label><span>作品 IP</span><select v-model="form.franchiseId"><option value="">未选择</option><option v-for="item in catalog?.franchises" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label><span>角色</span><select v-model="form.characterId"><option value="">未选择</option><option v-for="item in catalog?.characters.filter(v=>!form.franchiseId||v.franchiseId===form.franchiseId)" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label><span>材质</span><input v-model="form.material" placeholder="PVC、ABS…"></label><label><span>比例</span><input v-model="form.scale" placeholder="1/7、无比例…"></label><label><span>厂商</span><input v-model="form.manufacturer"></label><label><span>版权信息</span><input v-model="form.copyrightNotice"></label><label class="full"><span>中文描述</span><textarea v-model="form.descriptionZhCn" rows="4"/></label><label class="full"><span>英文描述</span><textarea v-model="form.descriptionEnUs" rows="3"/></label></div><div class="section-title"><h3>SKU 规格</h3><button type="button" @click="addSku">＋ 添加 SKU</button></div><div v-for="(sku,index) in form.skus" :key="index" class="repeat"><div class="grid sku"><label><span>商家编码 *</span><input v-model="sku.code" required></label><label><span>规格名称 *</span><input v-model="sku.nameZhCn" required></label><label><span>条码</span><input v-model="sku.barcode"></label><label><span>价格（分）</span><input v-model.number="sku.priceAmount" type="number" min="0"></label><label><span>初始库存</span><input v-model.number="sku.initialStock" type="number" min="0"></label><label><span>重量（克）</span><input v-model.number="sku.weightGrams" type="number" min="0"></label></div><button type="button" class="remove" @click="form.skus.splice(index,1)">移除</button></div><div class="section-title"><h3>图片与视频预留</h3><button type="button" @click="addMedia">＋ 添加媒体</button></div><div v-for="(media,index) in form.media" :key="index" class="repeat media"><input v-model="media.fileId" placeholder="已上传文件 ID" required><select v-model="media.kind"><option value="IMAGE">图片</option><option value="VIDEO">视频（预留）</option></select><input v-model="media.altZhCn" placeholder="中文 Alt"><button type="button" :class="{cover:media.isCover}" @click="setCover(index)">{{media.isCover?'封面':'设为封面'}}</button><button type="button" class="remove" @click="form.media.splice(index,1)">移除</button></div></div><footer><span>保存草稿不要求填写全部上架资料</span><button type="button" @click="modal=false">取消</button><button class="primary" :disabled="busy">{{busy?'保存中…':'保存草稿'}}</button></footer></form></div></Teleport></section></template>

<style scoped lang="less">.product-page{background:var(--app-bg)}.shell{max-width:1220px;margin:auto}.hero{display:flex;align-items:center;justify-content:space-between;padding:34px 38px;border:1px solid var(--border);border-radius:22px;background:linear-gradient(120deg,var(--accent-soft),var(--surface) 58%)}.hero small,.drawer small{color:var(--accent);font-size:9px;font-weight:800;letter-spacing:.17em}.hero h1{margin:8px 0;color:var(--text);font-size:30px}.hero p{margin:0;color:var(--text-muted);font-size:12px}.hero button,.primary{padding:12px 17px;border:0;border-radius:10px;background:var(--accent);color:white;font-weight:700}.panel{padding:20px;margin-top:18px;border:1px solid var(--border);border-radius:18px;background:var(--surface);box-shadow:var(--shadow)}.filters{display:flex;gap:10px;margin-bottom:16px}.filters input{flex:1}.filters input,.filters select,input,select,textarea{padding:11px;border:1px solid var(--border);border-radius:9px;background:var(--surface-raised);color:var(--text);outline:none}.name{display:grid}.name b{color:var(--text)}.name small{margin-top:3px;color:var(--text-muted)}em{padding:5px 8px;border-radius:99px;background:var(--accent-soft);color:var(--accent);font-size:9px;font-style:normal}.actions{display:flex;justify-content:flex-end;gap:6px}.actions button,.section-title button{border:0;background:none;color:var(--accent);cursor:pointer}.danger,.remove{color:#df5b76!important}.error{padding:12px;border-radius:10px;background:#ffe5ec;color:#c74360}.loading{padding:40px;text-align:center}.mask{position:fixed;z-index:100;inset:0;display:flex;justify-content:flex-end;background:#17142380}.drawer{display:flex;width:min(850px,95vw);height:100%;flex-direction:column;background:var(--surface);color:var(--text);box-shadow:-25px 0 65px #0003}.drawer>header{display:flex;align-items:center;justify-content:space-between;padding:22px 28px;border-bottom:1px solid var(--border)}.drawer h2{margin:5px 0}.drawer>header>button{border:0;background:none;color:var(--text);font-size:26px}.form-scroll{flex:1;overflow:auto;padding:10px 28px 35px}.form-scroll h3{margin:22px 0 12px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:13px}.grid label{display:grid;gap:6px}.grid label span{font-size:10px;color:var(--text-muted)}.grid .full{grid-column:1/-1}.section-title{display:flex;align-items:center;justify-content:space-between;margin-top:25px}.repeat{position:relative;padding:15px;margin-bottom:10px;border:1px solid var(--border);border-radius:12px;background:var(--surface-raised)}.repeat>.remove{position:absolute;right:10px;top:8px;border:0;background:none}.media{display:grid;grid-template-columns:2fr 1fr 2fr auto auto;gap:8px}.cover{color:#149878!important}.drawer>footer{display:flex;align-items:center;justify-content:flex-end;gap:10px;padding:16px 28px;border-top:1px solid var(--border)}.drawer>footer span{margin-right:auto;color:var(--text-muted);font-size:10px}.drawer>footer button{padding:10px 15px;border:1px solid var(--border);border-radius:9px;background:var(--surface-raised);color:var(--text)}.drawer>footer .primary{border:0;background:var(--accent);color:white}@media(max-width:700px){.hero{align-items:flex-start;flex-direction:column;gap:20px}.grid{grid-template-columns:1fr}.grid .full{grid-column:auto}.media{grid-template-columns:1fr}.drawer>footer span{display:none}}</style>
